//#region src/private/url.ts
const EXAMPLE_BASE_URL = "https://example.com";
const hrefToUrl = (href, pathname) => {
	if (href.startsWith("/")) return new URL(`${EXAMPLE_BASE_URL}${href}`);
	if (pathname.endsWith("/") || href.startsWith("#") || href.startsWith("?")) return new URL(`${EXAMPLE_BASE_URL}${pathname}${href}`);
	return new URL(`${EXAMPLE_BASE_URL}${pathname}/${href}`);
};
const parseInternalHref = (href, location, propagateSearchParams) => {
	const { hash, pathname, searchParams } = hrefToUrl(href, location.pathname);
	const priorSearchParams = new URLSearchParams(location.search);
	for (const key of propagateSearchParams) {
		const value = priorSearchParams.get(key);
		if (value !== null) searchParams.set(key, value);
	}
	return {
		hash,
		pathname,
		search: searchParams.toString()
	};
};
const isExternalHref = (href) => /^[a-z][a-z0-9+.-]*:|^\/\//i.test(href);
//#endregion
export { isExternalHref, parseInternalHref };
